    pub fn length_after_transformations(s: String, t: i32, nums: Vec<i32>) -> i32 {
        let mut T = Mat::new();
        for i in 0..L {
            for j in 1..=nums[i] as usize {
                T.a[(i + j) % L][i] = 1;
            }
